public class Iterable2 {
    static class CountDown implements Iterable<Integer> {
        final int start;
        CountDown(int start) { this.start = start; }
        public java.util.Iterator<Integer> iterator() {
            return new java.util.Iterator<>() {
                int cur = start;
                public boolean hasNext() { return cur > 0; }
                public Integer next() { return cur--; }
            };
        }
    }
    public static void main(String[] args) {
        for (int n : new CountDown(4)) System.out.print(n + " ");
    }
}
